module counter_12(
    input rst_n,
    input clk,
    input valid_count,
    output reg [3:0] out
); 
    parameter state_0 = 4'b0000;
    parameter state_1 = 4'b0001;
    reg [3:0] state;
    always @(posedge clk) begin
        if (!rst_n) begin
            state <= state_0;
            out <= 4'b0000;
        end
        else begin
            case (state)
                state_0: begin
                    if (valid_count && !rst_n) begin
                        out <= 4'b0000;
                        state <= state_1;
                    end
                    else if (valid_count && out == 4'd11) begin
                        out <= 4'b0000;
                        state <= state_0;
                    end
                    else if (valid_count) begin
                        out <= out + 1;
                        state <= state_1;
                    end
                end
                state_1: begin
                    if (valid_count && !rst_n) begin
                        out <= 4'b0000;
                        state <= state_0;
                    end
                    else if (valid_count && out == 4'd11) begin
                        out <= 4'b0000;
                        state <= state_0;
                    end
                    else if (valid_count) begin
                        out <= out + 1;
                        state <= state_1;
                    end
                end
            endcase
        end
    end
endmodule
